 1	import type { FC } from 'react';
 2	
 3	import type { ResourceField } from '@components/common/utils/types';
 4	import { ConcernsTable } from '@components/Concerns/components/ConcernsTable';
 5	import { ROW_TYPE, type RowNode } from '@components/VsphereFoldersTable/utils/types';
 6	import { Tbody, Td, Tr } from '@patternfly/react-table';
 7	import { isEmpty } from '@utils/helpers';
 8	
 9	import FolderTreeRow from '../FolderTreeRow/FolderTreeRow';
10	import TreeTableEmptyState from '../TreeTableEmptyState/TreeTableEmptyState';
11	import VmTreeRow from '../VmTreeRow/VmTreeRow';
12	
13	type TreeTableBodyProps = {
14	  pagedRows: RowNode[];
15	  columns: ResourceField[];
16	  groupVMCountByFolder: Map<string, number>;
17	  clearAllFilters: () => void;
18	  hasFiltersApplied: boolean;
19	  showAll: boolean;
20	};
21	
22	const TreeTableBody: FC<TreeTableBodyProps> = ({
23	  clearAllFilters,
24	  columns,
25	  groupVMCountByFolder,
26	  hasFiltersApplied,
27	  pagedRows,
28	  showAll,
29	}) => {
30	  const colSpan = columns.length + 1;
31	  if (isEmpty(pagedRows)) {
32	    return (
33	      <TreeTableEmptyState
34	        clearAllFilters={clearAllFilters}
35	        colSpan={colSpan}
36	        hasFiltersApplied={hasFiltersApplied}
37	      />
38	    );
39	  }
40	
41	  return (
42	    <Tbody>
43	      {pagedRows
44	        .filter((row) => (showAll ? true : row.isSelected))
45	        .map((row) => {
46	          if (row.type === ROW_TYPE.Folder) {
47	            return (
48	              <FolderTreeRow key={row.key} row={row} groupVMCountByFolder={groupVMCountByFolder} />
49	            );
50	          }
51	
52	          if (row.type === ROW_TYPE.Vm) {
53	            return <VmTreeRow key={row.key} row={row} columns={columns} />;
54	          }
55	
56	          if (row.type === ROW_TYPE.Concerns) {
57	            return (
58	              <Tr key={row.key} isHidden={row.isHidden}>
59	                <Td colSpan={colSpan}>
60	                  <ConcernsTable vmData={row.vmData} />
61	                </Td>
62	              </Tr>
63	            );
64	          }
65	
66	          return null;
67	        })}
68	    </Tbody>
69	  );
70	};
71	
72	export default TreeTableBody;

